下面是一个**生产级**的 `debounce` 函数实现，涵盖基础用法、leading / trailing 控制以及 `maxWait` 兜底：

## 基础版（最常用）

```javascript
/**
 * 创建一个防抖函数——在连续调用时，只在最后一次调用
 * 结束后等待 `delay` 毫秒后执行。
 *
 * @param {Function} fn      要执行的函数
 * @param {number}   delay   延迟的毫秒数
 * @returns {Function} 防抖后的函数
 */
function debounce(fn, delay) {
  let timer = null;

  return function (...args) {
    // 每次调用都清除上一次的定时器
    if (timer) clearTimeout(timer);

    // 重新设定定时器
    timer = setTimeout(() => {
      fn.apply(this, args);   // 保留 this 指向
      timer = null;
    }, delay);
  };
}
```

---

## 完整版（支持 leading / trailing / maxWait）

```javascript
/**
 * 可配置的防抖函数
 *
 * @param {Function} fn
 * @param {number}   delay      延迟毫秒数
 * @param {Object}   options
 * @param {boolean}  [options.leading=false]  是否在延迟开始前立即执行一次
 * @param {boolean}  [options.trailing=true]  是否在延迟结束后执行（若 leading=true
 *                                            且同一周期内只调用了一次，该次仍会被
 *                                            执行一次；trailing=false 且 leading=true
 *                                            则只有首次调用会立即执行，后续不执行）
 * @param {number}   [options.maxWait]        最大等待时间，保证函数在该时间内
 *                                            至少执行一次（类似 throttle）
 * @returns {Function}
 */
function debounce(fn, delay, options = {}) {
  const {
    leading  = false,
    trailing = true,
    maxWait,
  } = options;

  let timer    = null;
  let lastArgs = null;
  let lastThis = null;
  let lastCallTime = 0;
  let lastInvokeTime = 0;

  function invoke(time) {
    lastInvokeTime = time;
    fn.apply(lastThis, lastArgs);
    lastArgs = lastThis = null;
  }

  function startTimer(pendingFunc, wait) {
    return setTimeout(pendingFunc, wait);
  }

  function remainingWait(time) {
    const timeSinceLastCall = time - lastCallTime;
    const timeSinceLastInvoke = time - lastInvokeTime;
    const timeWaiting = delay - timeSinceLastCall;

    // 如果设置了 maxWait，保证不超过 maxWait 就执行一次
    return maxWait !== undefined
      ? Math.min(timeWaiting, maxWait - timeSinceLastInvoke)
      : timeWaiting;
  }

  function shouldInvoke(time) {
    const timeSinceLastCall  = time - lastCallTime;
    const timeSinceLastInvoke = time - lastInvokeTime;

    // 以下任意条件满足即执行：
    // 1. 首次调用 (lastCallTime === 0)
    // 2. 已超过 delay
    // 3. 系统时间被回拨
    // 4. 超过了 maxWait
    return (
      lastCallTime === 0 ||
      timeSinceLastCall >= delay ||
      timeSinceLastCall < 0 ||
      (maxWait !== undefined && timeSinceLastInvoke >= maxWait)
    );
  }

  function trailingEdge(time) {
    timer = null;

    // trailing 执行：只在 trailing=true 且最后一次调用有参数时执行
    if (trailing && lastArgs) {
      invoke(time);
    }
    lastArgs = lastThis = null;
  }

  function leadingEdge(time) {
    // 立即执行一次
    lastInvokeTime = time;
    invoke(time);
    // 启动 trailing 定时器
    timer = startTimer(timerExpired, delay);
  }

  function timerExpired() {
    const time = Date.now();
    if (shouldInvoke(time)) {
      return trailingEdge(time);
    }
    // 还没到时间，重新计时剩余时间
    timer = startTimer(timerExpired, remainingWait(time));
  }

  function debounced(...args) {
    const time = Date.now();
    const isInvoking = shouldInvoke(time);

    lastArgs = args;
    lastThis = this;
    lastCallTime = time;

    if (isInvoking) {
      if (timer === null) {
        // leading 模式：立即执行
        return leadingEdge(time);
      }
      if (maxWait !== undefined) {
        // 即使有 timer，但 maxWait 到了也要执行
        timer = clearTimeout(timer);
        return leadingEdge(time);
      }
    }

    // 没有 timer 时启动一个新的
    if (timer === null) {
      timer = startTimer(timerExpired, delay);
    }

    return undefined;
  }

  /**
   * 取消尚未执行的防抖调用
   */
  debounced.cancel = function () {
    if (timer) clearTimeout(timer);
    timer = null;
    lastArgs = lastThis = null;
    lastCallTime = lastInvokeTime = 0;
  };

  /**
   * 立即执行 pending 的调用（如果有的话）
   */
  debounced.flush = function () {
    if (timer && lastArgs) {
      invoke(Date.now());
      if (timer) clearTimeout(timer);
      timer = null;
      lastArgs = lastThis = null;
    }
  };

  return debounced;
}
```

---

## 使用示例

```javascript
// 搜索输入防抖（基础版）
const onSearch = debounce(async (query) => {
  const res = await fetch(`/api/search?q=${query}`);
  // 渲染结果...
}, 300);

searchInput.addEventListener('input', (e) => {
  onSearch(e.target.value);
});

// 按钮防连点（leading 版：立刻执行第一次，300ms 内不再响应）
const onClick = debounce(
  () => console.log('提交！'),
  300,
  { leading: true, trailing: false }
);

submitBtn.addEventListener('click', onClick);

// 页面 resize 节流防抖混合（maxWait 保证至少 500ms 执行一次）
window.addEventListener('resize', debounce(
  () => console.log('re-layout'),
  200,
  { maxWait: 500 }
));
```

---

### 要点总结

| 模式 | leading | trailing | 行为 |
|------|---------|----------|------|
| **默认防抖** | false | true | 等待停止后执行（搜索输入） |
| **前缘防抖** | true | false | 立即执行，后续忽略（提防连点） |
| **前缘+后缘** | true | true | 立即执行 + 冷却结束后再执行一次 |
| **maxWait 兜底** | — | — | 保证函数在 N ms 内至少执行一次（类似 throttle） |

另外还提供了 `.cancel()`（取消 pending 调用）和 `.flush()`（立即执行 pending 调用）两个工具方法，方便组件卸载时清理。

